import tkinter as tk
import random

class TicTacToe:
    def __init__(self, root):
        self.root = root
        self.root.title("Tic Tac Toe vs Computer")
        self.current_player = "X"  # Human starts
        self.game_over = False
        self.buttons = [[None for _ in range(3)] for _ in range(3)]

        # Create game board
        for i in range(3):
            for j in range(3):
                self.buttons[i][j] = tk.Button(
                    root,
                    text="",
                    font=('normal', 20),
                    height=2,
                    width=5,
                    command=lambda row=i, col=j: self.on_click(row, col)
                )
                self.buttons[i][j].grid(row=i, column=j)

        # Status label
        self.status = tk.Label(root, text="Your turn (X)", font=('normal', 14))
        self.status.grid(row=3, column=0, columnspan=3)

        # Reset button
        self.reset_button = tk.Button(root, text="Reset Game", command=self.reset_game)
        self.reset_button.grid(row=4, column=0, columnspan=3)

    def on_click(self, row, col):
        if self.game_over or self.buttons[row][col]["text"] != "":
            return

        self.buttons[row][col]["text"] = self.current_player
        self.check_winner()

        if not self.game_over:
            self.current_player = "O"  # Switch to computer
            self.status.config(text="Computer's turn (O)")
            self.root.update()  # Force GUI update
            self.computer_move()
            self.current_player = "X"  # Switch back to human
            self.status.config(text="Your turn (X)")
            self.check_winner()

    def computer_move(self):
        available_moves = []
        for i in range(3):
            for j in range(3):
                if self.buttons[i][j]["text"] == "":
                    available_moves.append((i, j))

        # Simple AI: choose random available move
        row, col = random.choice(available_moves)
        self.buttons[row][col]["text"] = "O"

    def check_winner(self):
        # Check rows, columns, and diagonals
        for i in range(3):
            if self.buttons[i][0]["text"] == self.buttons[i][1]["text"] == self.buttons[i][2]["text"] != "":
                self.game_over = True
                self.status.config(text=f"{self.buttons[i][0]['text']} wins!")
                self.highlight_winner(i, 0, i, 2)
                return
            if self.buttons[0][i]["text"] == self.buttons[1][i]["text"] == self.buttons[2][i]["text"] != "":
                self.game_over = True
                self.status.config(text=f"{self.buttons[0][i]['text']} wins!")
                self.highlight_winner(0, i, 2, i)
                return

        if self.buttons[0][0]["text"] == self.buttons[1][1]["text"] == self.buttons[2][2]["text"] != "":
            self.game_over = True
            self.status.config(text=f"{self.buttons[0][0]['text']} wins!")
            self.highlight_winner(0, 0, 2, 2)
            return
        if self.buttons[0][2]["text"] == self.buttons[1][1]["text"] == self.buttons[2][0]["text"] != "":
            self.game_over = True
            self.status.config(text=f"{self.buttons[0][2]['text']} wins!")
            self.highlight_winner(0, 2, 2, 0)
            return

        # Check for tie
        if all(cell["text"] != "" for row in self.buttons for cell in row):
            self.game_over = True
            self.status.config(text="Game tied!")

    def highlight_winner(self, start_row, start_col, end_row, end_col):
        for i in range(start_row, end_row + 1):
            for j in range(start_col, end_col + 1):
                self.buttons[i][j].config(bg="lightgreen")

    def reset_game(self):
        for i in range(3):
            for j in range(3):
                self.buttons[i][j]["text"] = ""
                self.buttons[i][j].config(bg="SystemButtonFace")
        self.game_over = False
        self.current_player = "X"
        self.status.config(text="Your turn (X)")

if __name__ == "__main__":
    root = tk.Tk()
    game = TicTacToe(root)
    print("Tic Tac Toe game started. Run the script to play!")
    root.mainloop()